CREATE TABLE IF NOT EXISTS machakos_sublocation_villages (
    id BIGSERIAL PRIMARY KEY,
    county TEXT NOT NULL DEFAULT 'Machakos',
    subcounty TEXT NOT NULL,
    ward TEXT NOT NULL,
    sublocation TEXT NOT NULL,
    village TEXT NOT NULL,
